import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return base premium for a single sword for a new customer on their first policy");
    it.todo("should return correct base premiums for each main item type (amulet, staff, potion)");
    it.todo("should return base premium for a single component");
    it.todo("should apply a reduced premium for a building block of three alike components");
    it.todo("should apply a 50% cursed surcharge on item base premium");
    it.todo("should apply a 30% enchantment surcharge for items with enchantment level >= 5");
    it.todo("should apply a 20% loyalty discount for customers with >= 2 years with MHPCO");
    it.todo("should apply a 10% initial assessment surcharge on a first insurance");
    it.todo("should apply a 15% discount on each contract after the first");
    it.todo("should add a 5 G processing fee to every premium");
  });

  describe("claim", () => {
    it.todo("should return payout as damage minus the 100 G deductible");
    it.todo("should cap total payouts at twice the insurance sum across multiple claims");
    it.todo("should reimburse damage to enchantment >= 8 items at 50% of the damage amount");
    it.todo("should fully reimburse damage to items made of dragon material");
  });
});

