const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25,
};

const PROCESSING_FEE = 5;
const INITIAL_ASSESSMENT_SURCHARGE_PCT = 10;

